VALUES
  ('social-worker-moex-07310', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關信度和效度之敘述，那一個敘述是不正確？', '["一個有效的測量是可信的", "信度指測量工具之穩定性，重複測量可以得到相同的結果之意思", "效度指測量工具之穩定性，重複測量可以得到相同的結果之意思", "效度指測量工具能真正測出我們想要測量之變項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07311', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '科學提供了公認的實相（agreement reality）和經驗的實相（experiential reality）的方法稱為科學方法 （scientific method）。因此科學方法應該包含那些元素：', '["實證的、永久的、主觀的", "實證的、有系統的、尋求因果關係的", "主觀的、永久的、有系統的", "客觀的、不變的、有系統的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07312', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '用來記錄真實的外在行為，並且可以蒐集到無法用言語描寫的資料，同時可以避免掉被研究對象拒絕配 合之窘境，但是無法問到研究對象第一手調查意見之研究方法，稱之為：', '["觀察法", "實驗法", "訪談法", "紮根研究"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07313', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社工所同學小馬想研究家暴中心新進社工員角色期望、角色關係與督導機制之相關因素探討。下列敘 述，何者正確？', '["為了研究的準確性與客觀性，小馬一定得到家暴中心實習不可", "此三變項間，角色關係稱為中介變項", "此研究之自變項為新進社工員之角色期望", "此研究之分析單位（unit of analysis）為家暴中心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07314', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '以下四種狀況，何者正確？', '["為了受訪者人權及隱私權，縱使做深度質性訪談研究，我們也不應該直接接觸案主，而是跟他（她） 的主責社工談就好", "實務機構應加強研究能力，將服務經驗轉化成研究能量，但是因為實務工作者工作忙碌，所以應把握 與學校教授產學合作之機會，多多參與研究之掛名，此稱為雙贏政策", "為了增加學者做研究之樣本來源及增加研究效度，各社福機構不得拒絕提供案主之名冊", "為了掌握郵寄問卷之回收情形，研究者在回郵信封上加以編號，此種作法是明顯違反研究倫理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07315', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '調查研究是一種科學的社會工作研究方法。可以讓研究者在有限的資源與人力中，探討問題的真相。以 下敘述，請問何者正確？', '["問卷設計非常重要，因此我們不會將自變項與依變項同時放進問卷設計中", "抽樣方法依研究目的而異，但是一般以隨機抽樣最能控制干擾因素", "為了使填答率提升，因此我們要儘量找帥哥辣妹當訪員", "為了提高研究可靠性，所以最好只做質性訪談"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07316', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一個好的研究，文獻探討是不可或缺的一部分，請問下列有關文獻探討的敘述，何者為非？', '["文獻探討可以幫助我們確定問題所在，幫助我們了解變項間之對立概念", "文獻探討的目的之一是為了使我們知道那些題目以前已經被研究過？研究結果又是如何", "文獻探討的目的不是為了讓我們東抄西抄，但是為了可以有較好的概念，因此我們要儘量參考碩士論文", "文獻探討是呈現研究邏輯的重要過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07317', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '立基於某個外在標準，作為所要測量之相同變數的另一個指標或測量工具，我們稱之為：', '["預測效度（predictive validity）", "同時效度（concurrent validity）", "效標關聯效度（criterion-related validity）", "內在一致性信度（internal consistency reliability）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07318', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者，是與研究分析單位有關的推論錯誤？', '["選擇性偏誤", "系統性偏誤", "分類學的謬誤", "生態學的謬誤 情況：小英的姑姑去年收養了一位2歲小孩，念社工研究所的小英想了解北部地區收養家庭的親子互動情形及 其家庭動力分析。依此回答下列第37題至第38題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07319', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請問小英該用甚麼樣的抽樣方法找到樣本？', '["滾雪球抽樣法（snowball sampling）", "配額抽樣法（quota sampling）", "系統抽樣法（systematic sampling）", "直接找姑姑問就好，用個案研究分析法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
